// Generated by Claude Opus 4.6

import { ValidatedOptions } from '@patternfly/react-core';
import { act, renderHook } from '@testing-library/react';

import { useRestoreFormValidation } from '@/pages/RestoreFromBackup/useRestoreFormValidation';

describe('useRestoreFormValidation', () => {
  test('should have initial state as default/empty', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    expect(result.current.workspaceName).toBe('');
    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.default);
    expect(result.current.workspaceNameError).toBe('');
    expect(result.current.workspaceNameWarning).toBe('');
  });

  test('should return success state for valid name', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    act(() => {
      result.current.setWorkspaceName('valid-name');
    });

    expect(result.current.workspaceName).toBe('valid-name');
    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.success);
    expect(result.current.workspaceNameError).toBe('');
  });

  test('should return error for name longer than 63 characters', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    const longName = 'a'.repeat(64);
    act(() => {
      result.current.setWorkspaceName(longName);
    });

    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.error);
    expect(result.current.workspaceNameError).toBe('Workspace name must be 63 characters or less.');
  });

  test('should return error for invalid characters', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    act(() => {
      result.current.setWorkspaceName('-invalid');
    });

    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.error);
    expect(result.current.workspaceNameError).toContain(
      'Must contain only lowercase letters, numbers, and hyphens',
    );
  });

  test('should return warning when name matches existing workspace AND matches backup name', () => {
    const existingNames = new Set(['my-workspace']);
    const { result } = renderHook(() => useRestoreFormValidation(existingNames, 'my-workspace'));

    act(() => {
      result.current.setWorkspaceName('my-workspace');
    });

    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.warning);
    expect(result.current.workspaceNameWarning).toContain('still exists on this cluster');
    expect(result.current.workspaceNameError).toBe('');
  });

  test('should return error when name matches existing workspace but NOT backup name', () => {
    const existingNames = new Set(['my-workspace']);
    const { result } = renderHook(() =>
      useRestoreFormValidation(existingNames, 'different-backup'),
    );

    act(() => {
      result.current.setWorkspaceName('my-workspace');
    });

    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.error);
    expect(result.current.workspaceNameError).toBe('A workspace with this name already exists.');
    expect(result.current.workspaceNameWarning).toBe('');
  });

  test('should sanitize input via handleWorkspaceNameChange', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    act(() => {
      result.current.handleWorkspaceNameChange('My_Workspace');
    });

    expect(result.current.workspaceName).toBe('myworkspace');
  });

  test('should return default state for empty name', () => {
    const { result } = renderHook(() => useRestoreFormValidation());

    act(() => {
      result.current.setWorkspaceName('valid-name');
    });
    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.success);

    act(() => {
      result.current.setWorkspaceName('');
    });
    expect(result.current.workspaceNameValidated).toBe(ValidatedOptions.default);
    expect(result.current.workspaceNameError).toBe('');
  });
});
